import { b as EmailConfig, a as EmailAddress, g as IEmailService } from './types-CCHryvHe.js';
export { f as EmailResult, E as EmailTemplate, S as SendEmailParams, h as SendTemplateParams } from './types-CCHryvHe.js';

/**
 * Email Service - Server Side
 *
 * Main entry point for server-side email functionality.
 * Use this in server functions, API routes, etc.
 *
 * @example
 * ```typescript
 * import { createEmail } from '@shogo-ai/sdk/email/server'
 *
 * // Auto-configured from environment variables
 * const email = createEmail()
 *
 * // Send a templated email
 * await email.sendTemplate({
 *   to: 'user@example.com',
 *   template: 'welcome',
 *   data: { name: 'Alice', appName: 'MyApp' },
 * })
 *
 * // Send raw email
 * await email.send({
 *   to: 'user@example.com',
 *   subject: 'Hello!',
 *   html: '<h1>Hello World</h1>',
 * })
 * ```
 */

/**
 * Options for creating an email service
 */
interface CreateEmailOptions {
    /**
     * Email provider configuration.
     * If not provided, auto-detects from environment variables.
     */
    config?: EmailConfig;
    /**
     * Default sender address.
     * Can also be set via EMAIL_FROM or SMTP_FROM_EMAIL env var.
     */
    defaultFrom?: EmailAddress;
    /**
     * Include built-in templates (welcome, password-reset, invitation, notification).
     * Default: true
     */
    includeBuiltins?: boolean;
}
/**
 * Create an email service instance.
 *
 * If no config is provided, auto-detects provider from environment variables:
 * - SMTP: SMTP_HOST, SMTP_PORT, SMTP_USER, SMTP_PASSWORD
 * - SES: AWS_REGION or SES_REGION
 *
 * @example
 * ```typescript
 * // Auto-configured from env
 * const email = createEmail()
 *
 * // With explicit SMTP config
 * const email = createEmail({
 *   config: {
 *     provider: 'smtp',
 *     defaultFrom: 'noreply@myapp.com',
 *     smtp: {
 *       host: 'smtp.example.com',
 *       port: 587,
 *       user: 'user',
 *       password: 'pass',
 *     },
 *   },
 * })
 *
 * // With SES config
 * const email = createEmail({
 *   config: {
 *     provider: 'ses',
 *     defaultFrom: 'noreply@myapp.com',
 *     ses: {
 *       region: 'us-east-1',
 *     },
 *   },
 * })
 * ```
 */
declare function createEmail(options?: CreateEmailOptions): IEmailService;
/**
 * Create an email service, returning null if not configured.
 * Useful for optional email functionality.
 *
 * @example
 * ```typescript
 * const email = createEmailOptional()
 *
 * if (email) {
 *   await email.send({ ... })
 * } else {
 *   console.log('Email not configured, skipping')
 * }
 * ```
 */
declare function createEmailOptional(options?: CreateEmailOptions): IEmailService | null;

export { type CreateEmailOptions, EmailConfig, IEmailService, createEmail, createEmailOptional };
